"use client";

import { useState } from "react";
import { calculateBond } from "@/lib/api";

export default function Page() {
  const [amount, setAmount] = useState("");
  const [type, setType] = useState("ROR");
  const [result, setResult] = useState(null);

  const handle = async () => {
    const data = await calculateBond({
      amount: Number(amount),
      type
    });
    setResult(data);
  };

  return (
    <div style={{ padding: 40 }}>
      <h1>Kalkulator obligacji</h1>

      <input
        value={amount}
        onChange={e => setAmount(e.target.value)}
        placeholder="Kwota"
      />

      <select value={type} onChange={e => setType(e.target.value)}>
        <option value="ROR">ROR</option>
        <option value="OTS">OTS</option>
      </select>

      <button onClick={handle}>Oblicz</button>

      {result && (
        <div>
          <p>Dziennie: {result.daily.toFixed(2)} zł</p>
          <p>Miesięcznie: {result.monthly.toFixed(2)} zł</p>
          <p>Rocznie: {result.yearly.toFixed(2)} zł</p>
        </div>
      )}
    </div>
  );
}